/* ============================================================
 * UART Driver
 * ============================================================ */

static void uart_init(void)
{
    /* Enable GPIOA and USART2 clocks */
    RCC_AHB1ENR |= (1 << 0);   /* GPIOA */
    RCC_APB1ENR |= (1 << 17);  /* USART2 */

    /* Configure PA2 (TX) and PA3 (RX) as alternate function (AF7) */
    uint32_t moder = GPIOA_MODER;
    moder &= ~(0x3 << (2 * 2));
    moder |= (0x2 << (2 * 2));   /* PA2 AF */
    moder &= ~(0x3 << (3 * 2));
    moder |= (0x2 << (3 * 2));   /* PA3 AF */
    GPIOA_MODER = moder;

    uint32_t afrl = GPIOA_AFRL;
    afrl &= ~(0xF << (2 * 4));
    afrl |= (7 << (2 * 4));      /* PA2 AF7 (USART2_TX) */
    afrl &= ~(0xF << (3 * 4));
    afrl |= (7 << (3 * 4));      /* PA3 AF7 (USART2_RX) */
    GPIOA_AFRL = afrl;

    /* Configure USART2: 115200 baud, 8N1 */
    USART2_CR1 = 0;
    USART2_CR2 = 0;
    USART2_CR3 = 0;

    /* Assuming 42 MHz APB1 clock: BRR = 42000000 / 115200 = 364.58 ≈ 0x016D */
    USART2_BRR = 0x016D;

    /* Enable USART, TX, RX */
    USART2_CR1 = (1 << 13) | (1 << 3) | (1 << 2);
}

static void uart_send_char(char c)
{
    while (!(USART2_SR & (1 << 7))) {} /* Wait for TXE */
    USART2_DR = (uint32_t)c;
}

static void uart_send_string(const char *str)
{
    while (*str) {
        uart_send_char(*str++);
    }
}

static void uart_send_hex8(uint8_t val)
{
    const char hex[] = "0123456789ABCDEF";
    uart_send_char(hex[(val >> 4) & 0x0F]);
    uart_send_char(hex[val & 0x0F]);
}

static void uart_send_hex(uint32_t val)
{
    uart_send_string("0x");
    for (int i = 28; i >= 0; i -= 4) {
        uart_send_char("0123456789ABCDEF"[(val >> i) & 0xF]);
    }
}

static bool uart_rx_available(void)
{
    return (USART2_SR & (1 << 5)) != 0; /* RXNE */
}

static char uart_read_char(void)
{
    while (!uart_rx_available()) {}
    return (char)(USART2_DR & 0xFF);
}

