static uint32_t simple_hash(const char *str)
{
    uint32_t hash = 5381;
    while (*str) {
        hash = ((hash << 5) + hash) + (uint8_t)(*str++);
    }
    return hash;
}

static void audit_log_command(const char *cmd, uint8_t result)
{
    uint32_t idx = g_audit_index % AUDIT_LOG_SIZE;
    g_audit_log[idx].timestamp_ms = get_systick_ms();
    g_audit_log[idx].command_hash = simple_hash(cmd);
    g_audit_log[idx].result = result;
    g_audit_index++;

    /* In production, also write to persistent flash log */
}

/* ============================================================
 * Memory Access Security
 * ============================================================ */

static bool security_check_memory_access(uint32_t addr, uint32_t size)
{
    /* Check for integer overflow */
    if (addr + size < addr) {
        return false;
    }

    /* Enforce maximum dump size */
    if (size > DIAG_MAX_DUMP_SIZE) {
        return false;
    }

    /* Check alignment */
    if (addr % 4 != 0) {
        return false;
    }

    /* First check forbidden regions - these always deny */
    for (uint32_t i = 0; i < NUM_FORBIDDEN_REGIONS; i++) {
        if (addr < forbidden_regions[i].end &&
            (addr + size) > forbidden_regions[i].start) {
            uart_send_string("[DENIED] Access to protected region: ");
            uart_send_string(forbidden_regions[i].name);
            uart_send_string("\r\n");
            return false;
        }
    }

    /* Then check if entirely within an allowed region */
    for (uint32_t i = 0; i < NUM_ALLOWED_REGIONS; i++) {
        if (addr >= allowed_regions[i].start &&
            (addr + size) <= allowed_regions[i].end &&
            allowed_regions[i].read_allowed) {
            return true;
        }
    }

    /* Default deny - not in any allowed region */
    uart_send_string("[DENIED] Address not in allowed regions\r\n");
    return false;
}

/* ============================================================
 * Authentication
 * ============================================================ */

static void security_generate_challenge(uint8_t *challenge, uint8_t len)
{
    for (uint8_t i = 0; i < len; i += 4) {
        uint32_t rnd = hw_rng_get();
        uint8_t remaining = (len - i) < 4 ? (len - i) : 4;
        for (uint8_t j = 0; j < remaining; j++) {
            challenge[i + j] = (uint8_t)(rnd >> (j * 8));
        }
    }
}

static bool security_verify_auth_response(const uint8_t *response, uint8_t len)
{
    if (len != DIAG_RESPONSE_SIZE) {
        return false;
    }

    /* Compute expected response: HMAC-SHA256(key, challenge) */
    uint8_t expected[32];
    hmac_sha256(diag_auth_key, sizeof(diag_auth_key),
                g_diag_session.challenge, DIAG_CHALLENGE_SIZE,
                expected);

    /* Constant-time comparison to prevent timing attacks */
    volatile uint8_t diff = 0;
    for (uint8_t i = 0; i < 32; i++) {
        diff |= expected[i] ^ response[i];
    }

    /* Clear expected from stack */
    memset(expected, 0, sizeof(expected));

    return (diff == 0);
}

