static void cmd_auth_begin(void)
{
    if (g_diag_session.state == DIAG_STATE_LOCKED_OUT) {
        uint32_t elapsed = get_systick_ms() - g_diag_session.lockout_start_ms;
        if (elapsed < DIAG_LOCKOUT_DURATION_MS) {
            uart_send_string("[LOCKED] Too many failed attempts. Wait ");
            uint32_t remaining = (DIAG_LOCKOUT_DURATION_MS - elapsed) / 1000;
            /* Simple decimal print */
            char buf[12];
            int pos = 0;
            if (remaining == 0) { buf[pos++] = '0'; }
            else {
                uint32_t tmp = remaining;
                char rev[12];
                int rpos = 0;
                while (tmp > 0) { rev[rpos++] = '0' + (tmp % 10); tmp /= 10; }
                while (rpos > 0) { buf[pos++] = rev[--rpos]; }
            }
            buf[pos] = '\0';
            uart_send_string(buf);
            uart_send_string(" seconds\r\n");
            return;
        }
        /* Lockout expired */
        g_diag_session.state = DIAG_STATE_LOCKED;
        g_diag_session.auth_attempts = 0;
    }

    /* Generate and send challenge */
    security_generate_challenge(g_diag_session.challenge, DIAG_CHALLENGE_SIZE);
    g_diag_session.state = DIAG_STATE_CHALLENGE_SENT;

    uart_send_string("CHALLENGE: ");
    for (uint8_t i = 0; i < DIAG_CHALLENGE_SIZE; i++) {
        uart_send_hex8(g_diag_session.challenge[i]);
    }
    uart_send_string("\r\nRespond with: auth_response <hex_hmac>\r\n");
}

static uint8_t hex_char_to_nibble(char c)
{
    if (c >= '0' && c <= '9') return (uint8_t)(c - '0');
    if (c >= 'a' && c <= 'f') return (uint8_t)(c - 'a' + 10);
    if (c >= 'A' && c <= 'F') return (uint8_t)(c - 'A' + 10);
    return 0xFF;
}

static void cmd_auth_response(const char *hex_response)
{
    if (g_diag_session.state != DIAG_STATE_CHALLENGE_SENT) {
        uart_send_string("[ERROR] No pending challenge. Use 'auth' first.\r\n");
        return;
    }

    /* Parse hex response */
    uint8_t response[DIAG_RESPONSE_SIZE];
    uint8_t len = (uint8_t)strlen(hex_response);

    if (len != DIAG_RESPONSE_SIZE * 2) {
        uart_send_string("[ERROR] Invalid response length\r\n");
        g_diag_session.auth_attempts++;
        goto check_lockout;
    }

    for (uint8_t i = 0; i < DIAG_RESPONSE_SIZE; i++) {
        uint8_t hi = hex_char_to_nibble(hex_response[i * 2]);
        uint8_t lo = hex_char_to_nibble(hex_response[i * 2 + 1]);
        if (hi == 0xFF || lo == 0xFF) {
            uart_send_string("[ERROR] Invalid hex character\r\n");
            g_diag_session.auth_attempts++;
            goto check_lockout;
        }
        response[i] = (hi << 4) | lo;
    }

    if (security_verify_auth_response(response, DIAG_RESPONSE_SIZE)) {
        g_diag_session.state = DIAG_STATE_AUTHENTICATED;
        g_diag_session.session_start_ms = get_systick_ms();
        g_diag_session.last_activity_ms = get_systick_ms();
        g_diag_session.auth_attempts = 0;
        g_diag_session.command_count = 0;
        uart_send_string("[OK] Authenticated. Session timeout: 5 minutes.\r\n");
        audit_log_command("AUTH_SUCCESS", 0);
        return;
    }

    uart_send_string("[FAILED] Authentication failed\r\n");
    g_diag_session.auth_attempts++;
    audit_log_command("AUTH_FAILED", 1);

    /* Clear response from memory */
    memset(response, 0, sizeof(response));

check_lockout:
    if (g_diag_session.auth_attempts >= DIAG_MAX_AUTH_ATTEMPTS) {
        g_diag_session.state = DIAG_STATE_LOCKED_OUT;
        g_diag_session.lockout_start_ms = get_systick_ms();
        uart_send_string("[LOCKED] Too many failed attempts. Locked for 10 minutes.\r\n");
        audit_log_command("AUTH_LOCKOUT", 1);
    }
}

static void cmd_dump_memory(const char *args)
{
    if (g_diag_session.state != DIAG_STATE_AUTHENTICATED) {
        uart_send_string("[DENIED] Authentication required\r\n");
        return;
    }

    /* Parse address and size: "0xADDRESS SIZE" */
    uint32_t addr = 0;
    uint32_t size = 0;
    const char *p = args;

    /* Skip "0x" prefix if present */
    if (p[0] == '0' && (p[1] == 'x' || p[1] == 'X')) {
        p += 2;
    }

    /* Parse hex address */
    while (*p && *p != ' ') {
        uint8_t nibble = hex_char_to_nibble(*p);
        if (nibble == 0xFF) {
            uart_send_string("[ERROR] Invalid address format\r\n");
            return;
        }
        addr = (addr << 4) | nibble;
        p++;
    }

    /* Skip space */
    while (*p == ' ') p++;

    /* Parse decimal size */
    while (*p >= '0' && *p <= '9') {
        size = size * 10 + (uint32_t)(*p - '0');
        p++;
    }

    if (size == 0) {
        size = 16; /* Default dump size */
    }

    /* Security check */
    if (!security_check_memory_access(addr, size)) {
        audit_log_command("dump_memory:DENIED", 1);
        return;
    }

    /* Perform dump */
    uart_send_string("Memory dump at ");
    uart_send_hex(addr);
    uart_send_string(", ");
    uart_send_hex(size);
    uart_send_string(" bytes:\r\n");

    volatile uint8_t *ptr = (volatile uint8_t *)addr;
    for (uint32_t i = 0; i < size; i++) {
        if (i % 16 == 0) {
            uart_send_hex(addr + i);
            uart_send_string(": ");
        }
        uart_send_hex8(ptr[i]);
        uart_send_char(' ');
        if (i % 16 == 15 || i == size - 1) {
            uart_send_string("\r\n");
        }
    }

    g_diag_session.last_activity_ms = get_systick_ms();
    audit_log_command("dump_memory", 0);
}

static void cmd_read_flash(const char *args)
{
    if (g_diag_session.state != DIAG_STATE_AUTHENTICATED) {
        uart_send_string("[DENIED] Authentication required\r\n");
        return;
    }

    /* Parse sector number */
    uint32_t sector = 0;
    const char *p = args;
    while (*p >= '0' && *p <= '9') {
        sector = sector * 10 + (uint32_t)(*p - '0');
        p++;
    }

    /* Only allow reading the configuration sector */
    /* Sector mapping for STM32F4: sector 7 = 0x08060000-0x0807FFFF */
    uint32_t flash_addr;
    uint32_t flash_size;

    switch (sector) {
        case 7: /* Configuration sector only */
            flash_addr = 0x08060000;
            flash_size = 256; /* Only first 256 bytes */
            break;
        default:
            uart_send_string("[DENIED] Only configuration sector (7) is readable\r\n");
            audit_log_command("read_flash:DENIED", 1);
            return;
    }

    if (!security_check_memory_access(flash_addr, flash_size)) {
        audit_log_command("read_flash:DENIED", 1);
        return;
    }

    uart_send_string("Flash sector ");
    uart_send_hex(sector);
    uart_send_string(" at ");
    uart_send_hex(flash_addr);
    uart_send_string(":\r\n");

    volatile uint8_t *ptr = (volatile uint8_t *)flash_addr;
    for (uint32_t i = 0; i < flash_size; i++) {
        if (i % 16 == 0) {
            uart_send_hex(flash_addr + i);
            uart_send_string(": ");
        }
        uart_send_hex8(ptr[i]);
        uart_send_char(' ');
        if (i % 16 == 15) {
            uart_send_string("\r\n");
        }
    }

    g_diag_session.last_activity_ms = get_systick_ms();
    audit_log_command("read_flash", 0);
}

static void cmd_get_config(void)
{
    if (g_diag_session.state != DIAG_STATE_AUTHENTICATED) {
        uart_send_string("[DENIED] Authentication required\r\n");
        return;
    }

    /* Read non-sensitive configuration from flash config sector */
    volatile uint32_t *config = (volatile uint32_t *)0x08060000;

    uart_send_string("=== Device Configuration ===\r\n");
    uart_send_string("FW Version:    ");
    uart_send_hex(config[0]);
    uart_send_string("\r\n");

    uart_send_string("HW Revision:   ");
    uart_send_hex(config[1]);
    uart_send_string("\r\n");

    uart_send_string("Serial Number: ");
    uart_send_hex(config[2]);
    uart_send_hex(config[3]);
    uart_send_string("\r\n");

    uart_send_string("Sensor Type:   ");
    uart_send_hex(config[4]);
    uart_send_string("\r\n");

    uart_send_string("Sample Rate:   ");
    uart_send_hex(config[5]);
    uart_send_string(" Hz\r\n");

    uart_send_string("TX Interval:   ");
    uart_send_hex(config[6]);
    uart_send_string(" sec\r\n");

    uart_send_string("Uptime:        ");
    uart_send_hex(get_systick_ms() / 1000);
    uart_send_string(" sec\r\n");

    /* Explicitly do NOT print: encryption keys, network credentials, auth tokens */
    uart_send_string("(Sensitive fields redacted)\r\n");
    uart_send_string("============================\r\n");

    g_diag_session.last_activity_ms = get_systick_ms();
    audit_log_command("get_config", 0);
}

static void cmd_get_status(void)
{
    if (g_diag_session.state != DIAG_STATE_AUTHENTICATED) {
        uart_send_string("[DENIED] Authentication required\r\n");
        return;
    }

    uart_send_string("=== System Status ===\r\n");

    uart_send_string("Debugger attached: ");
    uart_send_string(security_detect_debugger() ? "YES (WARNING)" : "No");
    uart_send_string("\r\n");

    uart_send_string("Session commands:  ");
    uart_send_hex(g_diag_session.command_count);
    uart_send_string("\r\n");

    uart_send_string("Audit log entries: ");
    uart_send_hex(g_audit_index);
    uart_send_string("\r\n");

#ifdef BUILD_PRODUCTION
    uart_send_string("Build:             PRODUCTION\r\n");
#else
    uart_send_string("Build:             DEVELOPMENT\r\n");
#endif

    uart_send_string("Flash protection:  ");
    uint8_t rdp = (uint8_t)((FLASH_OPTCR >> 8) & 0xFF);
    if (rdp == 0xAA) uart_send_string("Level 0 (NONE)");
    else if (rdp == 0xCC) uart_send_string("Level 2 (PERMANENT)");
    else uart_send_string("Level 1");
    uart_send_string("\r\n");

    uart_send_string("=====================\r\n");

    g_diag_session.last_activity_ms = get_systick_ms();
    audit_log_command("get_status", 0);
}

static void cmd_view_audit_log(void)
{
    if (g_diag_session.state != DIAG_STATE_AUTHENTICATED) {
        uart_send_string("[DENIED] Authentication required\r\n");
        return;
    }

    uart_send_string("=== Audit Log ===\r\n");
    uart_send_string("Timestamp    CmdHash      Result\r\n");

    uint32_t start = (g_audit_index > AUDIT_LOG_SIZE) ?
                     (g_audit_index - AUDIT_LOG_SIZE) : 0;
    uint32_t end = g_audit_index;

    for (uint32_t i = start; i < end; i++) {
        uint32_t idx = i % AUDIT_LOG_SIZE;
        uart_send_hex(g_audit_log[idx].timestamp_ms);
        uart_send_string(" ");
        uart_send_hex(g_audit_log[idx].command_hash);
        uart_send_string(" ");
        switch (g_audit_log[idx].result) {
            case 0: uart_send_string("OK"); break;
            case 1: uart_send_string("DENIED"); break;
            case 2: uart_send_string("ERROR"); break;
            default: uart_send_string("???"); break;
        }
        uart_send_string("\r\n");
    }

    uart_send_string("=================\r\n");
    g_diag_session.last_activity_ms = get_systick_ms();
    audit_log_command("view_audit", 0);
}

static void cmd_logout(void)
{
    /* Clear session state */
    memset(g_diag_session.challenge, 0, sizeof(g_diag_session.challenge));
    g_diag_session.state = DIAG_STATE_LOCKED;
    g_diag_session.command_count = 0;
    uart_send_string("[OK] Session terminated\r\n");
    audit_log_command("logout", 0);
}

static void cmd_help(void)
{
    uart_send_string("\r\n=== Secure Diagnostic Console ===\r\n");
    uart_send_string("Authentication:\r\n");
    uart_send_string("  auth                    - Begin authentication\r\n");
    uart_send_string("  auth_response <hex>     - Submit HMAC response\r\n");
    uart_send_string("  logout                  - End session\r\n");
    uart_send_string("\r\nDiagnostic Commands (require auth):\r\n");
    uart_send_string("  dump_memory <addr> <sz> - Dump memory (restricted regions)\r\n");
    uart_send_string("  read_flash <sector>     - Read flash sector (config only)\r\n");
    uart_send_string("  get_config              - Show device configuration\r\n");
    uart_send_string("  get_status              - Show system status\r\n");
    uart_send_string("  view_audit              - View audit log\r\n");
    uart_send_string("  help                    - Show this help\r\n");
    uart_send_string("=================================\r\n\r\n");
}

/* ============================================================
 * Command Parser and Dispatcher
 * ============================================================ */

static void diag_execute_command(const char *cmd)
{
    /* Rate limiting */
    uint32_t now = get_systick_ms();
    if (now - g_diag_session.last_cmd_ms < DIAG_RATE_LIMIT_MS) {
        uart_send_string("[RATE LIMITED] Please wait\r\n");
        return;
    }
    g_diag_session.last_cmd_ms = now;
    g_diag_session.command_count++;

    /* Skip leading whitespace */
    while (*cmd == ' ') cmd++;

    /* Empty command */
    if (*cmd == '\0') return;

    /* Commands available without authentication */
    if (strcmp(cmd, "help") == 0 || strcmp(cmd, "?") == 0) {
        cmd_help();
        return;
    }

    if (strcmp(cmd, "auth") == 0) {
        cmd_auth_begin();
        return;
    }

    if (strncmp(cmd, "auth_response ", 14) == 0) {
        cmd_auth_response(cmd + 14);
        return;
    }

    if (strcmp(cmd, "logout") == 0) {
        cmd_logout();
        return;
    }

    /* All remaining commands require authentication */
    if (g_diag_session.state != DIAG_STATE_AUTHENTICATED) {
        uart_send_string("[DENIED] Please authenticate first. Type 'auth' to begin.\r\n");
        audit_log_command(cmd, 1);
        return;
    }

    /* Authenticated commands */
    if (strncmp(cmd, "dump_memory ", 12) == 0) {
        cmd_dump_memory(cmd + 12);
    } else if (strncmp(cmd, "dump_memory", 11) == 0) {
        uart_send_string("Usage: dump_memory <hex_addr> <size>\r\n");
        uart_send_string("Example: dump_memory 0x20004000 64\r\n");
    } else if (strncmp(cmd, "read_flash ", 11) == 0) {
        cmd_read_flash(cmd + 11);
    } else if (strncmp(cmd, "read_flash", 10) == 0) {
        uart_send_string("Usage: read_flash <sector_number>\r\n");
        uart_send_string("Only sector 7 (config) is accessible\r\n");
    } else if (strcmp(cmd, "get_config") == 0) {
        cmd_get_config();
    } else if (strcmp(cmd, "get_status") == 0) {
        cmd_get_status();
    } else if (strcmp(cmd, "view_audit") == 0) {
        cmd_view_audit_log();
    } else {
        uart_send_string("[ERROR] Unknown command: ");
        uart_send_string(cmd);
        uart_send_string("\r\nType 'help' for available commands\r\n");
        audit_log_command(cmd, 2);
    }
}

/* ============================================================
 * Session Timeout Management
 * ============================================================ */

static void diag_check_timeouts(void)
{
    if (g_diag_session.state == DIAG_STATE_AUTHENTICATED) {
        uint32_t now = get_systick_ms();

        /* Session timeout */
        if (now - g_diag_session.session_start_ms > DIAG_SESSION_TIMEOUT_MS) {
            uart_send_string("\r\n[TIMEOUT] Session expired. Please re-authenticate.\r\n");
            cmd_logout();
            return;
        }

        /* Inactivity timeout (2 minutes) */
        if (now - g_diag_session.last_activity_ms > 120000) {
            uart_send_string("\r\n[TIMEOUT] Inactivity timeout. Session closed.\r\n");
            cmd_logout();
            return;
        }
    }

    /* Challenge timeout - expire challenge after 60 seconds */
    if (g_diag_session.state == DIAG_STATE_CHALLENGE_SENT) {
        /* We don't track challenge send time separately, so use last_cmd_ms */
        if (get_systick_ms() - g_diag_session.last_cmd_ms > 60000) {
            uart_send_string("\r\n[TIMEOUT] Challenge expired. Use 'auth' again.\r\n");
            memset(g_diag_session.challenge, 0, sizeof(g_diag_session.challenge));
            g_diag_session.state = DIAG_STATE_LOCKED;
        }
    }
}

/* ============================================================
 * Character Processing (Line Editor)
 * ============================================================ */

static void diag_process_char(char c)
{
    /* Handle backspace */
    if (c == '\b' || c == 0x7F) {
        if (g_diag_session.cmd_pos > 0) {
            g_diag_session.cmd_pos--;
            uart_send_string("\b \b");
        }
        return;
    }

    /* Handle enter */
    if (c == '\r' || c == '\n') {
        uart_send_string("\r\n");
        g_diag_session.cmd_buffer[g_diag_session.cmd_pos] = '\0';

        if (g_diag_session.cmd_pos > 0) {
            diag_execute_command(g_diag_session.cmd_buffer);
        }

        g_diag_session.cmd_pos = 0;
        memset(g_diag_session.cmd_buffer, 0, sizeof(g_diag_session.cmd_buffer));

        /* Print prompt */
        if (g_diag_session.state == DIAG_STATE_AUTHENTICATED) {
            uart_send_string("diag> ");
        } else {
            uart_send_string("locked> ");
        }
        return;
    }

    /* Handle Ctrl+C */
    if (c == 0x03) {
        uart_send_string("\r\n");
        g_diag_session.cmd_pos = 0;
        memset(g_diag_session.cmd_buffer, 0, sizeof(g_diag_session.cmd_buffer));
        if (g_diag_session.state == DIAG_STATE_AUTHENTICATED) {
            uart_send_string("diag> ");
        } else {
            uart_send_string("locked> ");
        }
        return;
    }

    /* Only accept printable ASCII */
    if (c < 0x20 || c > 0x7E) {
        return;
    }

    /* Buffer the character */
    if (g_diag_session.cmd_pos < DIAG_MAX_CMD_LEN - 1) {
        g_diag_session.cmd_buffer[g_diag_session.cmd_pos++] = c;
        uart_send_char(c);
    }
}

/* ============================================================
 * Initialization
 * ============================================================ */

static void diag_init(void)
{
    /* Clear session state */
    memset(&g_diag_session, 0, sizeof(g_diag_session));
    g_diag_session.state = DIAG_STATE_LOCKED;

    /* Clear audit log */
    memset(g_audit_log, 0, sizeof(g_audit_log));
    g_audit_index = 0;

    /* Initialize UART */
    uart_init();

    /* CRITICAL: Disable JTAG/SWD in production */
    security_disable_jtag();

    /* Check for debugger attachment */
    security_anti_tamper_check();

    /* Print banner */
    uart_send_string("\r\n");
    uart_send_string("========================================\r\n");
    uart_send_string("  Industrial IoT Sensor - Diagnostic Console\r\n");
#ifdef BUILD_PRODUCTION
    uart_send_string("  BUILD: PRODUCTION (Secured)\r\n");
#else
    uart_send_string("  BUILD: DEVELOPMENT (Debug Enabled)\r\n");
#endif
    uart_send_string("  Authentication required for all commands\r\n");
    uart_send_string("  Type 'help' for available commands\r\n");
    uart_send_string("  Type 'auth' to begin authentication\r\n");
    uart_send_string("========================================\r\n");
    uart_send_string("locked> ");

    audit_log_command("SYSTEM_BOOT", 0);
}

/* ============================================================
 * Main Diagnostic Task
 * Call this from your main loop or RTOS task
 * ============================================================ */

void diag_task(void)
{
    /* Check for session timeouts */
    diag_check_timeouts();

    /* Periodic anti-tamper check */
    static uint32_t last_tamper_check = 0;
    if (get_systick_ms() - last_tamper_check > 10000) { /* Every 10 seconds */
        security_anti_tamper_check();
        last_tamper_check = get_systick_ms();
    }

    /* Process incoming characters */
    if (uart_rx_available()) {
        char c = uart_read_char();
        diag_process_char(c);
    }
}

/* ============================================================
 * Main Entry Point
 * ============================================================ */

int main(void)
{
    /* System clock configuration would go here */
    /* SysTick configuration: 1ms tick */
    /* Configure SysTick for 1ms interrupts */

    /* Initialize diagnostic console */
    diag_init();

    /* Main loop */
    while (1) {
        /* Run diagnostic console task */
        diag_task();

        /* Your other application tasks here */
        /* sensor_task(); */
        /* network_task(); */
        /* watchdog_kick(); */
    }

    return 0;
}